#include <bits/stdc++.h>
using namespace std;

struct Node {
    int val;
    Node* next;
    Node(int x) : val(x), next(NULL) {}
};

int find_cycle(Node* head) {
    Node* slow = head;
    Node* fast = head;
    while (fast && fast->next) {
        slow = slow->next;
        fast = fast->next->next;
        if (slow == fast) break;
    }
    if (!fast || !fast->next) return -1;

    slow = head;
    while (slow != fast) {
        slow = slow->next;
        fast = fast->next;
    }

    return slow->val;
}

int main() {
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    vector<int> next_pointers;
    int x;
    while (cin >> x) next_pointers.push_back(x);

    vector<Node*> nodes;
    for (int num : nums) nodes.push_back(new Node(num));

    for (int i = 0; i < next_pointers.size(); i++) {
        if (next_pointers[i] == -1) nodes[i]->next = NULL;
        else nodes[i]->next = nodes[next_pointers[i]];
    }

    cout << find_cycle(nodes[0]) << endl;
    return 0;
}
